import{pixelsToNumber}from"./utils";function getJQueryOffset(e){e=e.getBoundingClientRect();return{top:e.top+document.body.scrollTop,left:e.left+document.body.scrollLeft}}function getJQueryLeftAndTop(e){e=getComputedStyle(e,null);return{left:pixelsToNumber(e.left),top:pixelsToNumber(e.top)}}export{getJQueryOffset,getJQueryLeftAndTop};